query:
SELECT t.id, t.name, t.slug FROM tournaments t WHERE t.name LIKE '%Copa%' OR t.name LIKE '%World%';

SELECT tp.id, tp.key, tp.label, tp.order, tp.slots, tp.is_knockout 
FROM tournament_phases tp 
WHERE tp.tournament_id IN (SELECT id FROM tournaments WHERE name LIKE '%Copa%' OR name LIKE '%World%')
ORDER BY tp.order;

SELECT COUNT(*) as total_games FROM games WHERE tournament_id IN (SELECT id FROM tournaments WHERE name LIKE '%Copa%' OR name LIKE '%World%');

